          list-style: none;
          margin: 0;
          padding: 0;
          border: 1px solid var(--divider-color);
          border-radius: 12px;
          overflow: hidden;
          background: var(--card-background-color);
          display: grid;
        }

        .compact-week-row {
          display: grid;
          gap: 4px;
          align-items: start;
          padding: 8px 10px;
          border-bottom: 1px solid var(--divider-color);
          font-size: 0.83rem;
          line-height: 1.25;
        }

        .compact-week-row:last-child {
          border-bottom: none;
        }

        .compact-week-row.left-marked {
          border-left: 4px solid var(--primary-text-color);
          padding-left: 6px;
        }

        .compact-week-row.current {
          font-weight: 700;
        }

        .compact-top {
          display: flex;
          align-items: flex-start;
          justify-content: space-between;
          gap: 8px;
        }

        .compact-week {
          color: var(--secondary-text-color);
          min-width: 0;
          overflow-wrap: anywhere;
        }

        .compact-date {
          font-style: normal;
        }

        .compact-context {
          font-style: italic;
        }

