        .history-slot-detail,
        .history-slot-time,
        .history-event-action,
        .history-event-reason,
        .history-event-time {
          color: var(--secondary-text-color);
          font-size: 0.8rem;
        }

        .history-event-action {
          text-transform: uppercase;
          letter-spacing: 0.03em;
          font-size: 0.72rem;
        }

        .modal-actions {
          display: flex;
          flex-wrap: wrap;
          justify-content: flex-end;
          gap: 8px;
          margin-top: 4px;
        }

        .btn {
          cursor: pointer;
          min-height: 36px;
          padding: 8px 12px;
